// capacity-test/scenarios/peak-load.js  (k6 script)
import http from 'k6/http';
import { check, sleep } from 'k6';
import { Rate, Trend } from 'k6/metrics';

const errorRate = new Rate('error_rate');
const llmLatency = new Trend('llm_latency_ms', true);

const PEAK_MULTIPLIER = __ENV.PEAK_MULTIPLIER || '1';
const BASE_VUS = 50; // base concurrent users
const TARGET_VUS = BASE_VUS * parseInt(PEAK_MULTIPLIER);

export const options = {
  stages: [
    { duration: '5m', target: TARGET_VUS },   // ramp up
    { duration: '20m', target: TARGET_VUS },  // sustain peak
    { duration: '5m', target: 0 },            // ramp down
  ],
  thresholds: {
    'llm_latency_ms{p:95}': ['p(95)<2000'],  // P95 < 2000ms
    'error_rate': ['rate<0.02'],              // < 2% errors
    'http_req_failed': ['rate<0.02'],
  },
};

const prompts = JSON.parse(open('../prompts/representative_corpus.json'));

export default function () {
  const prompt = prompts[Math.floor(Math.random() * prompts.length)];
  const start = Date.now();

  const res = http.post(
    `${__ENV.AGENT_API_URL}/v1/complete`,
    JSON.stringify({ prompt, max_tokens: 256 }),
    { headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${__ENV.API_KEY}` } }
  );

  llmLatency.add(Date.now() - start);
  errorRate.add(res.status !== 200);
  check(res, { 'status 200': (r) => r.status === 200 });
  sleep(1);
}
